const { Pool } = require('pg');
const fs = require('fs');
const path = require('path');

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function migrate() {
  const client = await pool.connect();
  try {
    // Create migrations tracking table
    await client.query(`
      CREATE TABLE IF NOT EXISTS _migrations (
        id SERIAL PRIMARY KEY,
        name VARCHAR(255) UNIQUE NOT NULL,
        applied_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Core tables
    await client.query(`
      CREATE TABLE IF NOT EXISTS users (
        id SERIAL PRIMARY KEY,
        email VARCHAR(255) UNIQUE NOT NULL,
        password_hash VARCHAR(255),
        name VARCHAR(255),
        role VARCHAR(50) DEFAULT 'candidate',
        company_name VARCHAR(255),
        github_username VARCHAR(255),
        avatar_url TEXT,
        is_paid BOOLEAN DEFAULT false,
        stripe_subscription_id VARCHAR(255),
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS jobs (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        title VARCHAR(255) NOT NULL,
        company VARCHAR(255),
        description TEXT,
        requirements TEXT,
        location VARCHAR(255),
        salary_range VARCHAR(100),
        job_type VARCHAR(50) DEFAULT 'full-time',
        status VARCHAR(50) DEFAULT 'active',
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS interviews (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        job_id INTEGER REFERENCES jobs(id) ON DELETE SET NULL,
        interview_type VARCHAR(50) DEFAULT 'mock',
        status VARCHAR(50) DEFAULT 'pending',
        questions JSONB DEFAULT '[]',
        responses JSONB DEFAULT '[]',
        ai_feedback JSONB,
        overall_score INTEGER,
        duration_seconds INTEGER,
        video_urls JSONB DEFAULT '[]',
        created_at TIMESTAMP DEFAULT NOW(),
        completed_at TIMESTAMP
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS interview_questions (
        id SERIAL PRIMARY KEY,
        category VARCHAR(100),
        difficulty VARCHAR(50) DEFAULT 'medium',
        question_text TEXT NOT NULL,
        ideal_answer_points JSONB DEFAULT '[]',
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS agent_data (
        id SERIAL PRIMARY KEY,
        type VARCHAR(100) NOT NULL,
        data JSONB NOT NULL,
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Run migration files from migrations folder
    const migrationsDir = path.join(__dirname, 'migrations');
    if (fs.existsSync(migrationsDir)) {
      const files = fs.readdirSync(migrationsDir)
        .filter(f => f.endsWith('.js'))
        .sort();

      for (const file of files) {
        const migration = require(path.join(migrationsDir, file));
        const existing = await client.query(
          'SELECT id FROM _migrations WHERE name = $1',
          [migration.name]
        );

        if (existing.rows.length === 0) {
          console.log(`Running migration: ${migration.name}`);
          await client.query('BEGIN');
          try {
            await migration.up(client);
            await client.query(
              'INSERT INTO _migrations (name) VALUES ($1)',
              [migration.name]
            );
            await client.query('COMMIT');
            console.log(`Migration ${migration.name} completed`);
          } catch (err) {
            await client.query('ROLLBACK');
            throw err;
          }
        }
      }
    }

    console.log('All migrations completed successfully');
  } catch (err) {
    console.error('Migration error:', err);
    process.exit(1);
  } finally {
    client.release();
    await pool.end();
  }
}

migrate();

# OpenAI Proxy - Utility AI Only

The OpenAI proxy is for **utility AI tasks** only - NOT for the product's AI features.

## When to Use This

- Embeddings (vector search, similarity)
- Image generation (DALL-E)
- OCR / document extraction
- Image analysis

## When NOT to Use This

If your AI feature is the **core product** (analyzing, recommending, generating content for users), use the **Polsia Agent API** instead. See the Agent SDK skill.

## Setup

```javascript
const OpenAI = require('openai');
const openai = new OpenAI(); // Uses OPENAI_BASE_URL and OPENAI_API_KEY from env
```

## Embeddings

```javascript
const embedding = await openai.embeddings.create({
  model: 'text-embedding-3-small',
  input: 'Text to embed'
});

const vector = embedding.data[0].embedding;
```

## Image Generation

```javascript
const image = await openai.images.generate({
  model: 'dall-e-3',
  prompt: 'A cute cat',
  size: '1024x1024'
});

const imageUrl = image.data[0].url;
```

## OCR / Document Extraction

```javascript
const response = await openai.chat.completions.create({
  model: 'gpt-4',
  task: 'ocr',  // or 'document-extraction'
  messages: [{
    role: 'user',
    content: [{
      type: 'image_url',
      image_url: { url: imageUrl }
    }]
  }]
});

const extractedText = response.choices[0].message.content;
```

## Image Analysis

```javascript
const response = await openai.chat.completions.create({
  model: 'gpt-4-vision-preview',
  messages: [{
    role: 'user',
    content: [
      { type: 'text', text: 'What is in this image?' },
      { type: 'image_url', image_url: { url: imageUrl } }
    ]
  }]
});
```

## DO NOT

```javascript
// WRONG - Don't use for product AI features
const response = await openai.chat.completions.create({
  model: 'gpt-4',
  messages: [{ role: 'user', content: 'Analyze this startup...' }]
});
```

For product AI features, use the Polsia Agent API (see Agent SDK skill).

# R2 Proxy - File Storage

Upload and manage files using Polsia's R2 storage proxy. Files are stored in Cloudflare R2 with automatic CDN delivery.

## Base URL

```
https://polsia.com/api/proxy/r2
```

## Authentication

All requests require the `POLSIA_API_KEY` header:

```javascript
headers: {
  'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`
}
```

## Upload a File

**Endpoint:** `POST /upload`

**Content-Type:** `multipart/form-data`

### Node.js with node-fetch (Recommended)

**IMPORTANT:** Use `node-fetch` instead of Node's native `fetch` for file uploads. Native fetch has compatibility issues with form-data streams that cause "Unexpected end of form" errors.

```javascript
const fetch = require('node-fetch');  // IMPORTANT: Use node-fetch, not native fetch
const FormData = require('form-data');

async function uploadToR2(fileBuffer, filename, mimeType) {
  const formData = new FormData();
  formData.append('file', fileBuffer, {
    filename,
    contentType: mimeType
  });

  const response = await fetch('https://polsia.com/api/proxy/r2/upload', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
      ...formData.getHeaders()  // CRITICAL: includes Content-Type with boundary
    },
    body: formData
  });

  const result = await response.json();
  if (!result.success) {
    throw new Error(result.error?.message || 'Upload failed');
  }
  return result.file.url;
}
```

### With Express + Multer

```javascript
const fetch = require('node-fetch');  // IMPORTANT: Use node-fetch
const multer = require('multer');
const FormData = require('form-data');

const upload = multer({ storage: multer.memoryStorage() });

app.post('/api/products', upload.single('image'), async (req, res) => {
  let imageUrl = null;

  if (req.file) {
    const formData = new FormData();
    formData.append('file', req.file.buffer, {
      filename: req.file.originalname,
      contentType: req.file.mimetype
    });

    const uploadRes = await fetch('https://polsia.com/api/proxy/r2/upload', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
        ...formData.getHeaders()
      },
      body: formData
    });

    const result = await uploadRes.json();
    if (result.success) {
      imageUrl = result.file.url;
    }
  }

  // Save product with imageUrl...
});
```

### Common Mistakes

```javascript
// WRONG #1 - Using native fetch (causes "Unexpected end of form" error)
const response = await fetch(url, { ... });  // Native fetch breaks form-data streams

// CORRECT - Use node-fetch
const fetch = require('node-fetch');
const response = await fetch(url, { ... });

// WRONG #2 - Missing formData.getHeaders()
const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'multipart/form-data'  // NO! Missing boundary
  },
  body: formData
});

// CORRECT - Use formData.getHeaders()
const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    ...formData.getHeaders()  // Includes Content-Type WITH boundary
  },
  body: formData
});
```

## Response Format

```json
{
  "success": true,
  "file": {
    "id": "uuid",
    "key": "company_123/abc123_image.jpg",
    "url": "https://cdn.polsia.com/company_123/abc123_image.jpg",
    "filename": "image.jpg",
    "mime_type": "image/jpeg",
    "size": 102400,
    "created_at": "2025-01-08T12:00:00Z"
  }
}
```

## List Files

```javascript
const response = await fetch('https://polsia.com/api/proxy/r2/files?limit=50', {
  headers: { 'Authorization': `Bearer ${process.env.POLSIA_API_KEY}` }
});
const { files, pagination } = await response.json();
```

## Delete File

```javascript
await fetch(`https://polsia.com/api/proxy/r2/files/${fileKey}`, {
  method: 'DELETE',
  headers: { 'Authorization': `Bearer ${process.env.POLSIA_API_KEY}` }
});
```

## Allowed File Types

- **Images:** jpeg, png, gif, webp
- **Videos:** mp4, webm, mov, avi, mpeg
- **Audio:** mp3, wav, ogg, m4a, aac, flac
- **Documents:** pdf, docx, pptx, xlsx, txt, csv

## Size Limits

- Images: 20MB
- Videos: 1GB
- Audio: 500MB
- Documents: 50MB

## Dependencies

Add to package.json:
```json
"node-fetch": "^2.7.0",
"form-data": "^4.0.0",
"multer": "^1.4.5-lts.1"
```

**Note:** Use `node-fetch` v2.x (not v3.x) for CommonJS compatibility.

// OmniScore Migration - Candidate Credit Score System
module.exports = {
  name: 'add_omniscore_tables',
  up: async (client) => {
    // OmniScore main table - stores current score and history
    await client.query(`
      CREATE TABLE IF NOT EXISTS omni_scores (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE UNIQUE,
        total_score INTEGER DEFAULT 300,
        interview_score INTEGER DEFAULT 0,
        technical_score INTEGER DEFAULT 0,
        resume_score INTEGER DEFAULT 0,
        behavior_score INTEGER DEFAULT 0,
        score_tier VARCHAR(50) DEFAULT 'new',
        last_updated TIMESTAMP DEFAULT NOW(),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Score components - individual score factors with time decay
    await client.query(`
      CREATE TABLE IF NOT EXISTS score_components (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        component_type VARCHAR(50) NOT NULL,
        source_type VARCHAR(50),
        source_id INTEGER,
        points INTEGER NOT NULL,
        max_points INTEGER NOT NULL,
        weight DECIMAL(3,2) DEFAULT 1.0,
        decay_rate DECIMAL(3,2) DEFAULT 0.95,
        metadata JSONB DEFAULT '{}',
        created_at TIMESTAMP DEFAULT NOW(),
        expires_at TIMESTAMP
      )
    `);

    // Score history - track score changes over time
    await client.query(`
      CREATE TABLE IF NOT EXISTS score_history (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        previous_score INTEGER,
        new_score INTEGER,
        change_amount INTEGER,
        change_reason VARCHAR(255),
        component_type VARCHAR(50),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Role-specific scores
    await client.query(`
      CREATE TABLE IF NOT EXISTS role_scores (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        role_name VARCHAR(100) NOT NULL,
        score INTEGER DEFAULT 300,
        interview_count INTEGER DEFAULT 0,
        last_updated TIMESTAMP DEFAULT NOW(),
        UNIQUE(user_id, role_name)
      )
    `);

    // Create indexes for performance
    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_score_components_user ON score_components(user_id);
      CREATE INDEX IF NOT EXISTS idx_score_history_user ON score_history(user_id);
      CREATE INDEX IF NOT EXISTS idx_role_scores_user ON role_scores(user_id);
    `);

    console.log('OmniScore tables created successfully');
  }
};

