// Verify document verification module is working
const fs = require('fs');
const path = require('path');

console.log('Verifying document verification setup...\n');

// Check files exist
const files = [
  './migrations/009_document_verification.js',
  './services/document-verification.js',
  './routes/documents.js',
  './public/documents.html',
  './public/js/documents.js'
];

let allFilesExist = true;
files.forEach(file => {
  const exists = fs.existsSync(file);
  console.log(`${exists ? '✓' : '✗'} ${file}`);
  if (!exists) allFilesExist = false;
});

if (!allFilesExist) {
  console.error('\nERROR: Some files are missing');
  process.exit(1);
}

// Check migration structure
console.log('\n--- Checking migration structure ---');
const migration = require('./migrations/009_document_verification.js');
if (migration.name && migration.up) {
  console.log('✓ Migration has name and up function');
} else {
  console.error('✗ Migration structure invalid');
  process.exit(1);
}

// Check service exports
console.log('\n--- Checking service exports ---');
const service = require('./services/document-verification.js');
const requiredFunctions = ['verifyDocument', 'applyDocumentScoresToOmniScore', 'logDocumentAccess'];
requiredFunctions.forEach(fn => {
  if (typeof service[fn] === 'function') {
    console.log(`✓ ${fn} exported`);
  } else {
    console.error(`✗ ${fn} missing or not a function`);
    process.exit(1);
  }
});

// Check routes
console.log('\n--- Checking routes ---');
const routes = require('./routes/documents.js');
console.log('✓ Document routes loaded successfully');

// Check server.js includes documents route
const serverContent = fs.readFileSync('./server.js', 'utf8');
if (serverContent.includes("require('./routes/documents')") &&
    serverContent.includes("app.use('/api/documents'")) {
  console.log('✓ Documents routes mounted in server.js');
} else {
  console.error('✗ Documents routes not properly mounted in server.js');
  process.exit(1);
}

console.log('\n✅ All verification checks passed!');
console.log('\nDocument verification system is ready to deploy.');

